// Get all metadata files from Google Drive API response
const response = $input.item.json;
const allFiles = response.files || [];

console.log('Total metadata files found:', allFiles.length);

// If only 1 or no files, don't delete anything
if (allFiles.length <= 1) {
  console.log('Only one or no metadata files - nothing to delete');
  return [];
}

// Sort by creation time to ensure newest is last
allFiles.sort((a, b) => {
  const dateA = new Date(a.createdTime);
  const dateB = new Date(b.createdTime);
  return dateA - dateB;
});

// Keep only the newest file (last in array), delete all others
const newestFile = allFiles[allFiles.length - 1];
const filesToDelete = allFiles.slice(0, -1); // All files except the last one

console.log('Newest file (keeping):', newestFile.name, 'created:', newestFile.createdTime);
console.log('Files to delete:', filesToDelete.length);

// Return array of files to delete
return filesToDelete.map(file => ({
  fileId: file.id,
  fileName: file.name,
  createdTime: file.createdTime
}));

// Export n8n Data Table to JSON

// Get all records from Data Table
const tableRecords = $('Get All Data Table Records').all();
const videos = tableRecords.map(item => item.json);

// Build metadata structure from Data Table
const newMetadata = {
  lastUpdated: new Date().toISOString(),
  totalVideos: videos.length,
  videos: videos
};

console.log('Built metadata from Data Table with', videos.length, 'videos');

// Get file ID from search results
let existingFileId = null;
try {
  const searchResult = $('Search for Metadata File').item;
  if (searchResult && searchResult.json && searchResult.json.id) {
    existingFileId = searchResult.json.id;
    console.log('Found existing metadata file with ID:', existingFileId);
  } else {
    console.log('No existing metadata file found');
  }
} catch (error) {
  console.log('No existing metadata file found');
}

// Convert to binary data for Google Drive upload
const jsonContent = JSON.stringify(newMetadata, null, 2);
const binaryData = Buffer.from(jsonContent, 'utf-8');

return {
  json: {
    fileName: $('Configuration').item.json.metadataFileName,
    existingFileId: existingFileId
  },
  binary: {
    data: {
      data: binaryData,
      mimeType: 'application/json',
      fileName: $('Configuration').item.json.metadataFileName
    }
  }
};

// Parse Instagram caption into structured fields
const caption = $('Filter Videos Only').item.json.caption || '';

// Find first hashtag position
const hashtagMatch = caption.match(/#/);
const firstHashtagIndex = hashtagMatch ? caption.indexOf('#') : -1;

let title = '';
let description = '';
const tagList = [];

if (firstHashtagIndex === -1) {
  // No hashtags - entire caption is title
  title = caption.trim();
  description = '';
} else {
  // Split at first hashtag
  title = caption.substring(0, firstHashtagIndex).trim();
  description = caption.substring(firstHashtagIndex).trim();
}

// Extract all hashtags
const hashtagMatches = caption.match(/#\w+/g);
if (hashtagMatches) {
  tagList.push(...hashtagMatches.map(tag => tag.substring(1)));
}

return {
  title: title,
  description: description,
  tagList: tagList,
  descriptionFull: caption
};

// Sort media items from earliest to latest by timestamp
const response = $input.item.json;
const mediaItems = response.data || [];

console.log('Total media items fetched:', mediaItems.length);

// Sort by timestamp - earliest first (ascending order)
mediaItems.sort((a, b) => {
  const dateA = new Date(a.timestamp);
  const dateB = new Date(b.timestamp);
  return dateA - dateB;
});

if (mediaItems.length > 0) {
  console.log('Earliest:', mediaItems[0].timestamp);
  console.log('Latest:', mediaItems[mediaItems.length - 1].timestamp);
}

return {
  json: {
    data: mediaItems,
    paging: response.paging
  }
};
